import{_ as a,o as s,c as i,a as n}from"./chunks/framework.BHSVNLI7.js";const g=JSON.parse('{"title":"Mini Config：从零设计一份精简的内核配置","description":"","frontmatter":{"title":"Mini Config：从零设计一份精简的内核配置","prerequisites":["wsl2-env-toolchain"],"next":["kernel-build"],"difficulty":"beginner","tags":["kconfig","allnoconfig","merge_config","arm64","kernel-config"],"architectures":["arm64"],"kernel_version":"6.19","sources":[{"notes":"document/notes/linux_kernel_programming/ch01.md"}]},"headers":[],"relativePath":"tutorials/foundations/kernel-mini-config.md","filePath":"tutorials/foundations/kernel-mini-config.md","lastUpdated":null}'),o={name:"tutorials/foundations/kernel-mini-config.md"};function c(d,e,t,l,r,p){return s(),i("div",null,[...e[0]||(e[0]=[n(`<h2 id="做什么" tabindex="-1">做什么 <a class="header-anchor" href="#做什么" aria-label="Permalink to &quot;做什么&quot;">​</a></h2><p>这篇我们要做一件很多人不会告诉你的事——亲手设计一份精简的内核配置，而不是无脑用 <code>defconfig</code>。最终我们会得到一份只包含 QEMU virt 机器启动所需最小功能集的内核配置，它只有 442 个 <code>=y</code> 配置项，而 <code>defconfig</code> 有 952 个。</p><p>啊，你说咱们这么快就动手嘛？对啊，不然呢？哈哈！咱们自己，亲手来配置一份内核，香不香？</p><h2 id="要了解什么" tabindex="-1">要了解什么 <a class="header-anchor" href="#要了解什么" aria-label="Permalink to &quot;要了解什么&quot;">​</a></h2><h3 id="defconfig-的问题" tabindex="-1">defconfig 的问题 <a class="header-anchor" href="#defconfig-的问题" aria-label="Permalink to &quot;defconfig 的问题&quot;">​</a></h3><p><code>defconfig</code> 是内核源码里预定义的默认配置，对于 ARM64 来说它位于 <code>arch/arm64/configs/defconfig</code>。跑一遍 <code>make defconfig</code> 就能得到一份&quot;能跑&quot;的内核配置，听起来很美好，问题是这份配置包含了大量真实 SoC 的驱动——GPU、音频、各种开发板的外设驱动等等。我们用 QEMU virt 机器做内核学习，根本不需要这些硬件支持，它们除了拖慢编译速度和分散注意力之外没有任何用处。</p><p>更直白地说，952 个 <code>=y</code> 项里面有超过一半是我们永远用不到的，编译出来多出的那几百个驱动在 QEMU 里也全都是 dead code。与其在一个臃肿的内核里学习，不如我们自己来裁剪。</p><h3 id="三步配置流程" tabindex="-1">三步配置流程 <a class="header-anchor" href="#三步配置流程" aria-label="Permalink to &quot;三步配置流程&quot;">​</a></h3><p>我们的策略是&quot;从零开始，按需开启&quot;，具体分三步走。</p><p>第一步，用 <code>allnoconfig</code> 生成一个几乎全关的基础配置。这个目标会让所有非必须的配置项都设为 <code>n</code>，只保留架构本身的硬性依赖。对于 ARM64 来说，生成的 <code>.config</code> 大约只有几十个选项是开着的，其他全部关闭。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> third_party/linux</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=aarch64-linux-gnu-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     O=../../out/build_latest_arm64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> allnoconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>第二步，用 <code>merge_config.sh</code> 把我们准备好的 config fragment 合并进去。这个脚本位于内核源码的 <code>scripts/kconfig/</code> 目录下，它的工作方式是把 fragment 文件里的配置项逐条合并到基础配置中——遇到 <code>=y</code> 就开启，遇到 <code>=m</code> 就设为模块。<code>-m</code> 参数后面跟的是目标 <code>.config</code> 文件路径：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/kconfig/merge_config.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    ../../out/build_latest_arm64/.config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    ../../configs/arm64-qemu-virt-learn.config</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>第三步，用 <code>olddefconfig</code> 让内核构建系统自动补齐所有依赖。我们手写的 fragment 只列了&quot;我们知道自己需要的&quot;选项，但内核配置之间有大量隐式依赖——比如开启了 <code>CONFIG_PRINTK=y</code>，它可能还依赖其他几个配置项。<code>olddefconfig</code> 会遍历整个配置树，把缺失的依赖全部自动补上，同时对新出现的配置项使用默认值：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=aarch64-linux-gnu-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     O=../../out/build_latest_arm64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> olddefconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>三步走完之后，最终的 <code>.config</code> 从几十项膨胀到了 442 项——多出来的那些全是 <code>olddefconfig</code> 自动补齐的依赖。这个数字依然只有 <code>defconfig</code> 的一半不到，而且每一个开启的配置项都能追溯到我们 fragment 里的某个明确需求。</p><h3 id="config-fragment-的设计思路" tabindex="-1">Config Fragment 的设计思路 <a class="header-anchor" href="#config-fragment-的设计思路" aria-label="Permalink to &quot;Config Fragment 的设计思路&quot;">​</a></h3><p>我们准备好的 fragment 文件是 <a href="./configs/arm64-qemu-virt-learn.config">configs/arm64-qemu-virt-learn.config</a>，它按功能分类组织，每一组都有注释说明&quot;为什么需要这些配置&quot;。当然，您可能会问这些都是啥。如果您不是很清楚——一个最好的办法就是递归下降法的查询相关的概念。我们这里快速的说一下这些内容都是啥：</p><p>先说平台基础。ARM64 架构本身是必须的，SMP（对称多处理器）也要开，因为我们后续的 QEMU 启动会配两个 CPU 核：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CONFIG_ARM64=y</span></span>
<span class="line"><span>CONFIG_64BIT=y</span></span>
<span class="line"><span>CONFIG_SMP=y</span></span>
<span class="line"><span>CONFIG_NR_CPUS=2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>接下来是串口控制台。QEMU virt 机器用 ARM PL011 UART 做串口输出，<code>console=ttyAMA0</code> 内核启动参数指向的就是它。不开这些配置的话，内核启动后你什么都看不到——没有启动日志，没有 shell 提示符，整个世界一片寂静：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CONFIG_TTY=y</span></span>
<span class="line"><span>CONFIG_SERIAL_AMBA_PL011=y</span></span>
<span class="line"><span>CONFIG_SERIAL_AMBA_PL011_CONSOLE=y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>然后是 initramfs 支持。我们的根文件系统会打包成 cpio.gz 格式作为 initrd 加载，内核必须支持 gzip 解压才能解包它：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CONFIG_BLK_DEV_INITRD=y</span></span>
<span class="line"><span>CONFIG_RD_GZIP=y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>文件系统方面，<code>devtmpfs</code> 让内核自动在 <code>/dev</code> 下创建设备节点，<code>procfs</code> 和 <code>sysfs</code> 分别提供 <code>/proc</code> 和 <code>/sys</code> 的内核信息接口，<code>tmpfs</code> 用于内存文件系统——这四个是 BusyBox shell 能正常工作的基本前提。内核模块相关的配置让我们后续可以加载和卸载 <code>.ko</code> 模块，而调试支持那一组（<code>DEBUG_INFO</code>、<code>GDB_SCRIPTS</code>、<code>KALLSYMS</code>）是为 GDB 远程调试准备的。</p><p>整个 fragment 大概 40 行，每个配置项都有一行注释说明它的用途和依赖关系。这种&quot;最小化 + 注释&quot;的方式让配置文件本身就成了一份学习笔记。</p><h3 id="踩坑记录" tabindex="-1">踩坑记录 <a class="header-anchor" href="#踩坑记录" aria-label="Permalink to &quot;踩坑记录&quot;">​</a></h3><p>这三步流程说起来简单，但实际操作的时候我们踩了不少坑，这里把最值得记录的几个列出来。</p><p><strong>&quot;The source tree is not clean&quot;</strong></p><p>这是最容易遇到的问题。内核 Makefile 里面有一个检查逻辑（在 <code>Makefile</code> 的 <code>outputmakefile</code> 目标中），当你使用 <code>O=</code> 分离编译目录时，它会检测源码树根目录下是否存在 <code>.config</code> 文件、<code>include/config/</code> 目录、或者 <code>arch/arm64/include/generated/</code> 目录。只要检测到其中任何一个，就会判定&quot;源码树不干净&quot;然后拒绝继续。</p><p>我们碰到的情况是这样的：之前直接在源码树里跑过 defconfig 测试，虽然后来用 <code>make mrproper</code> 清理了大部分产物，但 <code>merge_config.sh</code> 在执行过程中会在源码树根目录创建一个 <code>.config</code> 文件（这是它的一个副作用），导致后续的 <code>olddefconfig</code> 报错。解决办法很直接——手动删除残留的 <code>.config</code>：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> third_party/linux/.config</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>预防这个问题的核心原则是：用 <code>O=</code> 编译时，永远不要在源码树里直接跑 make。如果确实需要在源码树里操作（比如 <code>merge_config.sh</code>），操作完立刻检查并清理 <code>.config</code>。</p><p><strong>merge_config.sh 的参数</strong></p><p><code>-m</code> 参数后面跟的是目标 <code>.config</code> 文件的完整路径，不是目录路径。它直接就地修改这个文件，把 fragment 里的配置项合并进去。所以正确的调用方式是 <code>merge_config.sh -m &lt;output_dir&gt;/.config &lt;fragment&gt;</code>，而不是 <code>merge_config.sh -m &lt;output_dir&gt; &lt;fragment&gt;</code>。</p><p><strong>忘记设 ARCH 编译成了 x86</strong></p><p>这个坑真的很经典。内核构建系统根据 <code>ARCH</code> 变量决定目标架构，不设就默认宿主架构（WSL2 里是 x86_64）。<code>CROSS_COMPILE</code> 不设就用本机 gcc。结果就是 <code>make -j14</code> 跑完了，输出 <code>arch/x86/boot/bzImage is ready</code>——编译了半天全是白费。</p><p>解决办法有两个：要么每一行 make 命令都带 <code>ARCH=arm64 CROSS_COMPILE=aarch64-linux-gnu-</code>，要么在 shell 里 export 这两个变量。后者更省心，但要注意 export 只对当前 shell 会话有效，关掉终端重新开就得再设一次。</p><p><strong>工作目录与 make -C</strong></p><p>从项目根目录 <code>PenguinLab/</code> 直接跑 <code>make O=... Image</code> 会报 <code>No targets specified and no makefile found</code>，因为项目根目录没有内核的 Makefile。要么先 <code>cd third_party/linux</code> 再跑 make，要么用 <code>make -C third_party/linux</code> 显式指定源码目录。</p><h2 id="动手试试" tabindex="-1">动手试试 <a class="header-anchor" href="#动手试试" aria-label="Permalink to &quot;动手试试&quot;">​</a></h2><ol><li>确认 <code>third_party/linux/Makefile</code> 存在，如果不存在先运行 <code>./scripts/linux-submodule.sh init</code> 拉取内核源码</li><li>按顺序执行三步配置流程：<code>allnoconfig</code> → <code>merge_config.sh</code> → <code>olddefconfig</code>，注意每步都带 <code>ARCH</code> 和 <code>CROSS_COMPILE</code></li><li>用 <code>grep -c &quot;=y&quot; out/build_latest_arm64/.config</code> 统计最终配置项数量，应该看到 400-500 之间</li><li>用 <code>diff &lt;(grep &quot;=y&quot; out/build_latest_arm64/.config | sort) &lt;(grep &quot;=y&quot; &lt;(make ARCH=arm64 O=../../out/build_latest_arm64 defconfig &amp;&amp; cat ../../out/build_latest_arm64/.config) | sort)</code> 对比一下和 defconfig 的差距，看看我们砍掉了哪些东西</li></ol><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://www.kernel.org/doc/html/latest/kbuild/kbuild.html" target="_blank" rel="noreferrer">Kbuild 内核构建系统文档</a> — <code>ARCH</code>、<code>CROSS_COMPILE</code>、<code>O=</code> 等变量的官方定义</li><li><a href="https://docs.kernel.org/admin-guide/README.html" target="_blank" rel="noreferrer">Linux 内核构建说明</a> — kernel.org 官方的编译入门指南</li><li><a href="./configs/arm64-qemu-virt-learn.config">configs/arm64-qemu-virt-learn.config</a> — 我们的 mini config fragment 文件，每个配置项都有注释</li></ul>`,44)])])}const u=a(o,[["render",c]]);export{g as __pageData,u as default};
